#include <stdio.h>
#include <stdlib.h>
#include <string.h>


static int worked_cmem_sanitizers_static_analysis_fuzzing_4(int spatial, int temporal, int uninitialized, int race) {
  int tools = 0;
  if (spatial || temporal) tools |= 1;
  if (uninitialized) tools |= 2;
  if (race) tools |= 4;
  return tools;
}

int main(void) {
  int first = worked_cmem_sanitizers_static_analysis_fuzzing_4(1, 0, 0, 0);
  int changed = worked_cmem_sanitizers_static_analysis_fuzzing_4(0, 0, 1, 1);
